import ast
import operator

# Example safe evaluator for simple arithmetic expressions
OPERATORS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.Pow: operator.pow,
    ast.USub: operator.neg,
}

def _safe_eval(node):
    if isinstance(node, ast.Num):
        return node.n
    if isinstance(node, ast.BinOp):
        left = _safe_eval(node.left)
        right = _safe_eval(node.right)
        op_func = OPERATORS.get(type(node.op))
        if op_func is None:
            raise ValueError(f"Unsupported operator: {node.op}")
        return op_func(left, right)
    if isinstance(node, ast.UnaryOp):
        operand = _safe_eval(node.operand)
        op_func = OPERATORS.get(type(node.op))
        if op_func is None:
            raise ValueError(f"Unsupported unary operator: {node.op}")
        return op_func(operand)
    raise ValueError(f"Unsupported expression: {ast.dump(node)}")


def evaluate_formula(formula: str):
    """Safely evaluate a simple arithmetic expression using AST parsing."""
    try:
        parsed = ast.parse(formula, mode='eval')
        return _safe_eval(parsed.body)
    except Exception as e:
        raise ValueError("Invalid or unsafe formula") from e
